package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;

public class CSVFormatWithEscapeTest {

    @Test
    public void testWithEscape_primitiveChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        char escapeChar = '\\';

        CSVFormat result = original.withEscape(escapeChar);

        assertNotNull(result);
        assertEquals(Character.valueOf(escapeChar), result.getEscapeCharacter());
        // Ensure original is not modified (immutability)
        assertNotEquals(original.getEscapeCharacter(), result.getEscapeCharacter());
    }

    @Test
    public void testWithEscape_Character_null() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;

        // Using reflection to invoke private withEscape(Character)
        Method withEscapeCharMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
        withEscapeCharMethod.setAccessible(true);

        CSVFormat result = (CSVFormat) withEscapeCharMethod.invoke(original, (Character) null);

        assertNotNull(result);
        assertNull(result.getEscapeCharacter());
        assertNotSame(original, result);
    }

    @Test
    public void testWithEscape_Character_nonNull() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        Character escapeChar = Character.valueOf('"');

        // Using reflection to invoke private withEscape(Character)
        Method withEscapeCharMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
        withEscapeCharMethod.setAccessible(true);

        CSVFormat result = (CSVFormat) withEscapeCharMethod.invoke(original, escapeChar);

        assertNotNull(result);
        assertEquals(escapeChar, result.getEscapeCharacter());
        assertNotSame(original, result);
    }
}
